args.sparql:
SELECT ?quake ?magnitude ?label WHERE { 
  ?quake wdt:P31 wd:Q165 . 
  ?quake wdt:P276 ?location . 
  ?location wdt:P17 wd:Q30 . 
  { ?quake p:P2527/psv:P2527 ?magNode } 
  UNION 
  { ?quake p:P2528/psv:P2528 ?magNode } . 
  ?magNode wikibase:quantityAmount ?magRaw . 
  BIND(xsd:float(?magRaw) AS ?magnitude) . 
  OPTIONAL { ?quake rdfs:label ?label . FILTER(LANG(?label) = "en") } 
} 
ORDER BY DESC(?magnitude) 
LIMIT 1

SELECT ?quake ?magnitude ?label WHERE { 
  ?quake wdt:P31 wd:Q7289 . 
  ?quake wdt:P276 ?loc .
  ?loc wdt:P17 wd:Q30 .
